function navToggle(){isNavOpen()?navClose():navOpen()}function isNavOpen(){return navStyle=window.getComputedStyle(document.getElementById("sidenav")),navWidth=navStyle.getPropertyValue('width'),navWidth!=="0px"&&navWidth!==""}function navOpen(){let a="200px";document.getElementById("sidenav").style.width=a,document.getElementById("closebtn").style.left=a,window.matchMedia("(max-width: 650px)").matches||(document.getElementById("main").style.marginLeft=a)}function navClose(){document.getElementById("sidenav").style.width="0px",document.getElementById("main").style.marginLeft="0px",document.getElementById("closebtn").style.left="0px"}